CREATE OR REPLACE FUNCTION fpb_mem_controlid (as_memno char) RETURNS varchar AS $body$
DECLARE

  li_control_id integer;

BEGIN

  select  mp.control_id into STRICT li_control_id
  from sc_mem_m_membership_registered mb
      , sc_mem_m_ucf_member_group mg
      , sc_mem_m_ucf_province mp
  where mb.membership_no = as_memno
  and mb.member_group_no = mg.member_group_no
  and mg.province_code = mp.province_code;

  return li_control_id;


exception when others then return 0;
end;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
